"use client";

import { useAccount, useConnect, useDisconnect, useSwitchChain } from "wagmi";
import { injected } from "wagmi/connectors";
import { arbitrumSepolia } from "wagmi/chains";
import { shortenAddress } from "@/lib/utils";
import Link from "next/link";

export function Navbar() {
  const { address, isConnected, chainId } = useAccount();
  const { connect } = useConnect();
  const { disconnect } = useDisconnect();
  const { switchChain } = useSwitchChain();

  const isWrongNetwork = isConnected && chainId !== arbitrumSepolia.id;

  return (
    <nav className="border-b border-[#0E1117] bg-[#05050A]/90 backdrop-blur-md sticky top-0 z-50">
      {/* Top accent line */}
      <div className="h-[1px] bg-gradient-to-r from-transparent via-cyan-400/40 to-transparent" />

      <div className="max-w-6xl mx-auto px-4 h-14 flex items-center justify-between">
        {/* Logo */}
        <div className="flex items-center gap-8">
          <Link href="/" className="flex items-center gap-2.5 group">
            {/* Hex logo mark */}
            <div className="relative w-7 h-7">
              <div className="absolute inset-0 bg-cyan-400/10 rotate-45 rounded-sm group-hover:bg-cyan-400/20 transition-colors" />
              <div className="absolute inset-[3px] bg-cyan-400/20 rotate-45 rounded-sm" />
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-1.5 h-1.5 rounded-full bg-cyan-400 beacon" />
              </div>
            </div>
            <div className="flex flex-col leading-none">
              <span className="font-bold text-sm tracking-[0.15em] text-white uppercase">VEIL</span>
              <span className="text-[9px] text-cyan-400/60 tracking-widest uppercase font-mono">Protocol</span>
            </div>
          </Link>

          <div className="hidden md:flex items-center gap-6">
            <Link href="/" className="text-xs tracking-widest uppercase text-gray-500 hover:text-cyan-400 transition-colors font-mono">
              Dashboard
            </Link>
            <Link href="/create" className="text-xs tracking-widest uppercase text-gray-500 hover:text-cyan-400 transition-colors font-mono">
              New Position
            </Link>
          </div>
        </div>

        {/* Right side */}
        <div className="flex items-center gap-3">
          {isWrongNetwork && (
            <button
              onClick={() => switchChain({ chainId: arbitrumSepolia.id })}
              className="text-xs bg-red-950/50 border border-red-800/60 text-red-400 px-3 py-1.5 rounded font-mono hover:bg-red-950 transition-colors tracking-wide"
            >
              ⚠ Wrong Network
            </button>
          )}

          {isConnected ? (
            <div className="flex items-center gap-2">
              <div className="flex items-center gap-2 px-3 py-1.5 bg-[#0A0B0F] border border-[#1A1B22] rounded font-mono text-xs text-gray-400">
                <div className="w-1.5 h-1.5 rounded-full bg-cyan-400 beacon" />
                {shortenAddress(address!)}
              </div>
              <button
                onClick={() => disconnect()}
                className="text-[11px] text-gray-600 hover:text-gray-400 transition-colors px-2 font-mono tracking-wide"
              >
                [disconnect]
              </button>
            </div>
          ) : (
            <button
              onClick={() => connect({ connector: injected() })}
              className="btn-cyan relative text-xs font-mono tracking-widest uppercase bg-cyan-400/10 hover:bg-cyan-400/20 border border-cyan-400/40 text-cyan-400 px-4 py-2 rounded transition-all"
            >
              Connect Wallet
            </button>
          )}
        </div>
      </div>
    </nav>
  );
}
